fn m_AT_PREFIX(inp: &[u8], i: usize, fl: &mut Fl) -> isize {
    let len = inp.len();
    let mut p = i;
    let mut fail = false;
    fl.m_esc = false;
    if p + 7 > len { fl.hit_end = true; fail = true; } else if inp[p] == 64 && inp[p + 1] == 112 && inp[p + 2] == 114 && inp[p + 3] == 101 && inp[p + 4] == 102 && inp[p + 5] == 105 && inp[p + 6] == 120 { p += 7; } else { fail = true; }
    if fail { -1 } else { p as isize }
}

fn m_AT_BASE(inp: &[u8], i: usize, fl: &mut Fl) -> isize {
    let len = inp.len();
    let mut p = i;
    let mut fail = false;
    fl.m_esc = false;
    if p + 5 > len { fl.hit_end = true; fail = true; } else if inp[p] == 64 && inp[p + 1] == 98 && inp[p + 2] == 97 && inp[p + 3] == 115 && inp[p + 4] == 101 { p += 5; } else { fail = true; }
    if fail { -1 } else { p as isize }
}

